```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // Begin transaction
  auto begin_result = sqlgen::begin_transaction(conn);
  if (!begin_result) {
    return false;
  }

  // Read from_account balance
  auto read_result = (sqlgen::read<std::vector<Account>> | where("account_id"_c == from_account_id))(conn);
  if (!read_result) {
    sqlgen::rollback(conn);
    return false;
  }

  auto from_account = read_result.value()[0];

  // Check sufficient funds
  if (from_account.balance < amount) {
    sqlgen::rollback(conn);
    return false;
  }

  // Update from_account: balance = balance - amount (with condition)
  auto update_from_result = (sqlgen::update<Account>("balance"_c.set("balance"_c - amount)) | where("balance"_c >= amount))(conn);
  if (!update_from_result) {
    sqlgen::rollback(conn);
    return false;
  }

  // Update to_account: balance = balance + amount
  auto update_to_result = (sqlgen::update<Account>("balance"_c.set("balance"_c + amount)) | where("account_id"_c == to_account_id))(conn);
  if (!update_to_result) {
    sqlgen::rollback(conn);
    return false;
  }

  // Commit transaction
  auto commit_result = sqlgen::commit(conn);
  if (!commit_result) {
    sqlgen::rollback(conn);
    return false;
  }

  return true;
}

}  // namespace transaction_transfer_funds
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to "test_db.sqlite"

2. **Transaction Management**: 
   - Starts transaction with `sqlgen::begin_transaction()`
   - Commits on success with `sqlgen::commit()`
   - Rolls back on any failure with `sqlgen::rollback()`

3. **Data Reading**: Uses `sqlgen::read<std::vector<Account>>` with `where()` clause to fetch from_account balance

4. **Funds Validation**: Checks if `from_account.balance >= amount` before proceeding

5. **Update Operations**:
   - Uses `sqlgen::update<Account>()` with `set()` operations
   - First update subtracts amount from sender (with balance check)
   - Second update adds amount to receiver

6. **Error Handling**: Properly handles all Result types and ensures rollback on failures

The implementation follows the sqlgen library patterns demonstrated in the reference materials, using the fluent interface with pipe operators (`|`) to chain operations together in a readable manner.

