 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  // Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return {}; // Return empty vector on connection failure
  }

  // Read all sales data from the database
  auto sales_result = sqlgen::read<std::vector<Sales>>(*conn);
  if (!sales_result) {
    return {}; // Return empty vector on read failure
  }
  auto sales = *sales_result;

  // Create a map to store weekday totals
  std::map<int, int> weekday_totals;

  // Process each sale to extract weekday and aggregate quantities
  for (const auto& sale : sales) {
    // Extract weekday from sale_time using date_part function
    int weekday = sqlgen::date_part("weekday", &Sales::sale_time)(sale);

    // Add quantity to the corresponding weekday's total
    weekday_totals[weekday] += sale.quantity;
  }

  // Convert the map to the required vector format
  std::vector<WeekdayStats> result;
  for (const auto& [weekday, total_quantity] : weekday_totals) {
    result.push_back({.weekday = weekday, .total_quantity = total_quantity});
  }

  return result;
}

}  // namespace weekday_sales_analysis
